$(window).ready(function() {
	var settings = new script_settings('ajax');
	var do_not_ajax = false;

	var extractAjaxErrorMessage = function(xhr) {
		if (xhr && xhr.responseJSON && xhr.responseJSON.error) {
			return xhr.responseJSON.error;
		}

		if (xhr && typeof xhr.responseText === 'string' && xhr.responseText.length) {
			try {
				var parsed = JSON.parse(xhr.responseText);
				if (parsed && parsed.error) {
					return parsed.error;
				}
			} catch (_error) {
			}
		}

		return null;
	};

	// Enable submit button if disabled (cache problem)
	$('input[type="submit"]').removeAttr('disabled');
	
	var handle_form_submit = function() {
			if (do_not_ajax)
				return true;
			var form = this;
			var $wrappedForm = $(form);
			var $submit = $(form).find('input[type="submit"]');
			var submit_txt = $(this).find('input[type="submit"]').val();
			var is_reply_form = $(form).find('input[name="thread_id"], input[name="thread"]').length > 0;
			if (window.FormData === undefined)
				return true;
			if ($wrappedForm.data('ajax-posting')) {
				return false;
			}

			var resetSubmit = function() {
				$wrappedForm.removeData('ajax-posting');
				$submit.val(submit_txt);
				$submit.removeAttr('disabled');
			};

			var triggerAjaxAfterPost = function(post_response) {
				try {
					if (window.EirinchanFrontend && typeof window.EirinchanFrontend.dispatchAjaxAfterPostSuccess === 'function') {
						window.EirinchanFrontend.dispatchAjaxAfterPostSuccess(post_response, form);
					} else {
						$(document).trigger('ajax_after_post', [post_response, form]);
					}
				} catch (e) {
					console.error(e);
				}
			};

			var syncSeenForReply = function(post_response) {
				if (!is_reply_form || typeof window.markWatchedThreadSeen !== 'function') {
					return;
				}

				var threadId = parseInt($(form).find('input[name="thread_id"], input[name="thread"]').first().val(), 10);
				var boardUri = $(form).find('input[name="board"]').first().val();
				var watchLink = document.querySelector('.thread[data-thread-id="' + threadId + '"]');

				if (!threadId || !boardUri || !watchLink || watchLink.dataset.watched !== 'true') {
					return;
				}

				window.markWatchedThreadSeen(boardUri, threadId, post_response.id);
			};

			var syncThreadPageState = function(post_response) {
				if (!is_reply_form || !post_response) {
					return;
				}

				if (post_response.board_page_num) {
					$('#thread_stats_page').text(post_response.board_page_num);
				}

				if (post_response.board_page_path) {
					$('#thread-return, #thread-return-top').attr('href', post_response.board_page_path);
					$('#thread-refresh-target').attr('data-board-page-path', post_response.board_page_path);
				}

				if (post_response.board_page_num) {
					$('#thread-refresh-target').attr('data-board-page-num', post_response.board_page_num);
				}
			};


			var clearReplyFields = function() {
				$(form).find('input[name="subject"],input[name="file_url"],input[name="embed"],\
					textarea[name="body"],input[type="file"]').val('').change();
			};

			var formData = new FormData(this);
			formData.append('json_response', '1');
			formData.append('post', submit_txt);

			$(document).trigger("ajax_before_post", [formData, form]);

			var updateProgress = function(e) {
				var percentage;
				if (e.position === undefined) { // Firefox
					percentage = Math.round(e.loaded * 100 / e.total);
				}
				else { // Chrome?
					percentage = Math.round(e.position * 100 / e.total);
				}
				$(form).find('input[type="submit"]').val(_('Posting... (#%)').replace('#', percentage));
			};

			$wrappedForm.data('ajax-posting', true);

			$.ajax({
				url: this.action,
				type: 'POST',
				xhr: function() {
					var xhr = $.ajaxSettings.xhr();
					if(xhr.upload) {
						xhr.upload.addEventListener('progress', updateProgress, false);
					}
					return xhr;
				},
				success: function(post_response) {
					if (post_response.error) {
						if (post_response.banned) {
							// You are banned. Must post the form normally so the user can see the ban message.
							do_not_ajax = true;
							$(form).find('input[type="submit"]').each(function() {
								var $replacement = $('<input type="hidden">');
								$replacement.attr('name', $(this).attr('name'));
								$replacement.val(submit_txt);
								$(this)
									.after($replacement)
									.replaceWith($('<input type="button">').val(submit_txt));
							});
							$(form).submit();
						} else {
							alert(post_response.error);
							resetSubmit();
						}
					} else if (post_response.redirect && post_response.id) {
						if (is_reply_form) {
							$submit.val(_('Posted...'));
							var $reply = $('div.post#reply_' + post_response.id).first();

							if (post_response.html && !$reply.length) {
								var $newReply = $(post_response.html);
								var $lastPost = $('div.thread > div.post.reply:last');

								if ($lastPost.length) {
									var $after = $lastPost.nextAll('br.clear:first');
									if ($after.length) {
										$after.after($newReply);
									} else {
										$lastPost.after($newReply);
									}
								} else {
									var $op = $('div.thread > div.post.op, div.thread > div.op').first();
									var $afterOp = $op.nextAll('br.clear:first');
									if ($afterOp.length) {
										$afterOp.after($newReply);
									} else {
										$op.after($newReply);
									}
								}

								$reply = $('div.post#reply_' + post_response.id).first();
							}

							if ($reply.length) {
								var anchor = document.getElementById(String(post_response.id)) || $reply[0];

								try {
									if (typeof window.syncBacklinksFromPost === 'function') {
										window.syncBacklinksFromPost($reply[0]);
									}
								} catch (e) {
									console.error(e);
								}

								clearReplyFields();
								resetSubmit();
								syncSeenForReply(post_response);
								syncThreadPageState(post_response);
								triggerAjaxAfterPost(post_response);

								try {
									if (window.EirinchanFrontend && typeof window.EirinchanFrontend.dispatchNewPost === 'function') {
										window.EirinchanFrontend.dispatchNewPost($reply[0]);
									} else {
										$(document).trigger('new_post', $reply[0]);
									}
								} catch (e) {
									console.error(e);
								}

								window.requestAnimationFrame(function() {
									window.requestAnimationFrame(function() {
										try {
											if (history && history.replaceState) {
												history.replaceState(null, document.title, window.location.pathname + window.location.search + '#' + post_response.id);
											} else {
												window.location.hash = post_response.id;
											}
										} catch (_e) {
											window.location.hash = post_response.id;
										}

										if (anchor.scrollIntoView) {
											anchor.scrollIntoView({block: "start"});
										} else {
											$(window).scrollTop($reply.offset().top);
										}

										try {
											highlightReply(post_response.id);
										} catch (e) {
											console.error(e);
										}

										setTimeout(function() { $(window).trigger("scroll"); }, 50);
									});
								});
							} else {
								clearReplyFields();
								resetSubmit();
								syncSeenForReply(post_response);
								syncThreadPageState(post_response);
								triggerAjaxAfterPost(post_response);
								try {
									if (history && history.replaceState) {
										history.replaceState(null, document.title, window.location.pathname + window.location.search + '#' + post_response.id);
									} else {
										window.location.hash = post_response.id;
									}
								} catch (_e) {
									window.location.hash = post_response.id;
								}
								alert(_('Reply posted. Refresh to see it.'));
							}
						} else {
							triggerAjaxAfterPost(post_response)
							document.location = post_response.redirect;
						}
					} else {
						alert(_('An unknown error occured when posting!'));
						resetSubmit();
					}
				},
				error: function(xhr, status, er) {
					console.log(xhr);
					var extracted = extractAjaxErrorMessage(xhr);
					if (extracted) {
						alert(extracted);
					} else {
						alert(_('The server took too long to submit your post. Your post was probably still submitted. If it wasn\'t, we might be experiencing issues right now -- please try your post again later.'));
					}
					resetSubmit();
				},
				data: formData,
				cache: false,
				contentType: false,
				processData: false,
				complete: function() {
					if ($submit.val() !== _('Posted...')) {
						$wrappedForm.removeData('ajax-posting');
					}
				}
			}, 'json');
			
			$submit.val(_('Posting...'));
			$submit.attr('disabled', true);
			
			return false;
	};
	$(document).off('submit.ajax_post', 'form[data-post-form]');
	$(document).on('submit.ajax_post', 'form[data-post-form]', handle_form_submit);
});
/* End js/ajax.js */

/* Begin js/file-selector.js */
/*
 * file-selector.js - Add support for drag and drop file selection, and paste from clipboard on supported browsers.
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   $config['additional_javascript'][] = 'js/ajax.js';
 *   $config['additional_javascript'][] = 'js/file-selector.js';
 */
function init_file_selector(max_images, root) {
  if (/iPad|iPhone|iPod/.test(navigator.userAgent)) {
    return;
  }

  if (!(window.URL.createObjectURL && window.File)) {
    return;
  }

  if (typeof max_images === 'undefined') {
    max_images = 1;
  }

  var $root = root ? $(root) : $('form[name="post"]').first();
  if (!$root.length || $root.data('file-selector-initialized')) {
    return;
  }

  var $uploadCell = $root.find('#upload td, [data-upload-row] td').first();
  var $fileInput = $root.find('#upload_file, [data-upload-file]').first();
  var $dropzoneWrap = $uploadCell.find('.dropzone-wrap').first();

  if (!$uploadCell.length || !$fileInput.length || !$dropzoneWrap.length) {
    return;
  }

  var files = [];
  var selectorNamespace = '.file_selector_' + ($root.attr('id') || Math.floor(Math.random() * 1000000));
  var $dropzone = $dropzoneWrap.find('.dropzone').first();
  var $thumbs = $dropzoneWrap.find('.file-thumbs').first();

  if (!$dropzone.length || !$thumbs.length) {
    return;
  }

  $dropzoneWrap.css('user-select', 'none');
  $root.data('file-selector-initialized', true);

  function thumbContainerCount() {
    return $root.find('.tmb-container').length;
  }

  function updateArrowVisibility() {
    $root.find('.tmb-container').each(function(index, element) {
      var $el = $(element);
      $el.find('.move-up-btn').toggle(index !== 0);
      $el.find('.move-down-btn').toggle(index !== thumbContainerCount() - 1);
    });
  }

  function removeFile(file) {
    files.splice(files.indexOf(file), 1);
  }

  function getThumbElement(file) {
    return $root.find('.tmb-container').filter(function() {
      return $(this).data('file-ref') === file;
    });
  }

  function addThumb(file) {
    var fileName = (file.name.length < 24) ? file.name : file.name.substr(0, 22) + '…';
    var fileType = file.type.split('/')[0];
    var fileExt = (file.type.split('/')[1] || file.name.split('.').pop() || '').toUpperCase();

    var $container = $('<div>')
      .addClass('tmb-container')
      .data('file-ref', file)
      .append(
        $('<div>').addClass('tmb-controls').append(
          $('<div>').addClass('remove-btn').text('✖'),
          $('<div>').addClass('move-up-btn').text('⬆'),
          $('<div>').addClass('move-down-btn').text('⬇'),
          $('<div>').addClass('strip-fn-btn').text('strip filename')
        ),
        $('<div>').addClass('file-tmb'),
        $('<div>').addClass('tmb-filename').text(fileName)
      )
      .appendTo($thumbs);

    var $fileThumb = $container.find('.file-tmb');
    if (fileType === 'image') {
      var objURL = window.URL.createObjectURL(file);
      $fileThumb.css('background-image', 'url(' + objURL + ')');
    } else {
      $('<span>').text(fileExt).appendTo($fileThumb.empty());
    }

    updateArrowVisibility();
  }

  function addFile(file) {
    if (files.length === max_images) {
      return;
    }

    files.push(file);
    addThumb(file);
  }

  $root.on('click', '.move-up-btn', function(e) {
    e.stopPropagation();
    var $current = $(this).closest('.tmb-container');
    var file = $current.data('file-ref');
    var index = files.indexOf(file);

    if (index > 0) {
      var tmp = files[index - 1];
      files[index - 1] = files[index];
      files[index] = tmp;
      $current.insertBefore($current.prev());
      updateArrowVisibility();
    }
  });

  $root.on('click', '.move-down-btn', function(e) {
    e.stopPropagation();
    var $current = $(this).closest('.tmb-container');
    var file = $current.data('file-ref');
    var index = files.indexOf(file);

    if (index < files.length - 1) {
      var tmp = files[index + 1];
      files[index + 1] = files[index];
      files[index] = tmp;
      $current.insertAfter($current.next());
      updateArrowVisibility();
    }
  });

  $(document).on('ajax_before_post' + selectorNamespace, function(e, formData, form) {
    if (form !== $root[0]) {
      return;
    }

    if (max_images > 1) {
      for (var i = 0; i < max_images; i++) {
        if (typeof files[i] === 'undefined') break;
        formData.append('files[]', files[i]);
      }
      return;
    }

    for (var i = 0; i < max_images; i++) {
      if (typeof files[i] === 'undefined') break;
      formData.append('file', files[i]);
    }
  });

  $(document).on('ajax_after_post' + selectorNamespace, function(e, response, form) {
    if (form !== $root[0]) {
      return;
    }

    files = [];
    $root.find('.file-thumbs').empty();
  });

  $(document).on('click' + selectorNamespace, '.strip-fn-btn', function(e) {
    if (!$.contains($root[0], this)) {
      return;
    }

    e.stopPropagation();
    var $container = $(this).closest('.tmb-container');
    var index = $container.parent().children('.tmb-container').index($container);
    var file = files[index] || $container.data('file-ref');

    if (!file || !file.name) {
      return;
    }

    var extension = file.name.indexOf('.') !== -1 ? file.name.split('.').pop() : '';
    var newName = extension ? (Date.now() + '.' + extension) : String(Date.now());
    var newFile = new File([file.slice(0, file.size, file.type)], newName, { type: file.type });

    files[index] = newFile;
    $container.data('file-ref', newFile);
    $container.find('.tmb-filename').text(newName);
  });

  var dragCounter = 0;
  var dropTarget = $root[0];

  function cancelDragEvent(e) {
    e.stopPropagation();
    e.preventDefault();
  }

  function onDragEnter(e) {
    cancelDragEvent(e);

    if (dragCounter === 0) {
      $dropzone.addClass('dragover');
    }
    dragCounter++;
  }

  function onDragLeave(e) {
    cancelDragEvent(e);
    dragCounter--;
    if (dragCounter <= 0) {
      dragCounter = 0;
      $dropzone.removeClass('dragover');
    }
  }

  function onDrop(e) {
    cancelDragEvent(e);
    $dropzone.removeClass('dragover');
    dragCounter = 0;

    var fileList = e.dataTransfer.files;
    for (var i = 0; i < fileList.length; i++) {
      addFile(fileList[i]);
    }
  }

  ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(function(type) {
    dropTarget.addEventListener(type, cancelDragEvent, true);
  });
  dropTarget.addEventListener('dragenter', onDragEnter, true);
  dropTarget.addEventListener('dragleave', onDragLeave, true);
  dropTarget.addEventListener('drop', onDrop, true);

  $root.on('click', '.remove-btn', function(e) {
    e.stopPropagation();
    var file = $(e.target).closest('.tmb-container').data('file-ref');
    getThumbElement(file).remove();
    removeFile(file);
    updateArrowVisibility();
  });

  $dropzone.on('keypress click', function(e) {
    if ((e.which !== 1 || e.target.className !== 'file-hint') && e.which !== 13) {
      return;
    }

    e.stopPropagation();

    var $selector = $('<input type="file" multiple>');

    $selector.on('change', function() {
      if (this.files.length > 0) {
        for (var i = 0; i < this.files.length; i++) {
          addFile(this.files[i]);
        }
      }
      $(this).remove();
    });

    $selector.trigger('click');
  });

  $(document).on('paste' + selectorNamespace, function(e) {
    if (!$.contains($root[0], document.activeElement) && document.activeElement !== $root[0]) {
      return;
    }

    var clipboard = e.originalEvent.clipboardData;
    if (typeof clipboard.items === 'undefined' || clipboard.items.length === 0) {
      return;
    }

    for (var i = 0; i < clipboard.items.length; i++) {
      if (clipboard.items[i].kind !== 'file') {
        continue;
      }

      var file = new File([clipboard.items[i].getAsFile()], 'file.png', { type: 'image/png' });
      addFile(file);
    }
  });
}

$(function() {
  $('form[data-post-form]').each(function() {
    var maxImages = parseInt($(this).attr('data-max-images') || '1', 10);
    if (isNaN(maxImages) || maxImages < 1) {
      maxImages = 1;
    }

    init_file_selector(maxImages, this);
  });
});
/* End js/file-selector.js */

/* Begin js/upload-selection.js */
/*
 * upload-selection.js - makes upload fields in post form more compact
 * https://github.com/vichan-devel/Tinyboard/blob/master/js/upload-selection.js
 *
 * Released under the MIT license
 * Copyright (c) 2014 Marcin Łabanowski <marcin@6irc.net>
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   //$config['additional_javascript'][] = 'js/wpaint.js';
 *   $config['additional_javascript'][] = 'js/upload-selection.js';
 *                                                  
 */

$(function(){
  var enabled_url = $("#upload_url").length > 0;
  var enabled_embed = $("#upload_embed").length > 0;
  var enabled_oekaki = typeof window.oekaki != "undefined";

  var disable_all = function() {
    $("#upload").hide();
    $("[id^=upload_file]").hide();
    $(".file_separator").hide();
    $("#upload_url").hide();
    $("#upload_embed").hide();
    $(".add_image").hide();
    $(".dropzone-wrap").hide();

    if (enabled_oekaki) {
      if (window.oekaki.initialized) {
        window.oekaki.deinit();
      }
    }
  };

  enable_file = function() {
    disable_all();
    $("#upload").show();
    $(".dropzone-wrap").show();
    $(".file_separator").show();
    $("[id^=upload_file]").show();
    $(".add_image").show();
    if (enabled_embed) {
      $("#upload_embed").show();
    }
  };

  enable_url = function() {
    disable_all();
    $("#upload").show();
    $("#upload_url").show();

    $('label[for="file_url"]').html(_("URL"));
  };

  enable_embed = function() {
    enable_file();
    $("#upload_embed").show();
    $("#upload_embed").find('input[name=\"embed\"]').focus();
  };

  enable_oekaki = function() {
    disable_all();

    window.oekaki.init();
  };

  if (enabled_oekaki) {
    $("#confirm_oekaki_label").hide();
  }

  // The default file-upload state is rendered server-side.
  // Only keep the mode-switch helpers for explicit interactions.
});
/* End js/upload-selection.js */

/* Begin js/post-menu.js */
/*
 * post-menu.js - adds dropdown menu to posts
 *
 * Creates a global Menu object with four public methods:
 *
 *   Menu.onclick(fnc)
 *     registers a function to be executed after button click, before the menu is displayed
 *   Menu.add_item(id, text[, title])
 *     adds an item to the top level of menu
 *   Menu.add_submenu(id, text)
 *     creates and returns a List object through which to manipulate the content of the submenu
 *   Menu.get_submenu(id)
 *     returns the submenu with the specified id from the top level menu
 *
 *   The List object contains all the methods from Menu except onclick()
 *
 *   Example usage:
 *     Menu.add_item('filter-menu-hide', 'Hide post');
 *     Menu.add_item('filter-menu-unhide', 'Unhide post');
 *
 *     submenu = Menu.add_submenu('filter-menu-add', 'Add filter');
 *         submenu.add_item('filter-add-post-plus', 'Post +', 'Hide post and all replies');
 *         submenu.add_item('filter-add-id', 'ID');
 *  
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   $config['additional_javascript'][] = 'js/post-menu.js';
 */
$(document).ready(function () {

var List = function (menuId, text) {
	this.id = menuId;
	this.text = text;
	this.items = [];

	this.add_item = function (itemId, text, title) {
		this.items.push(new Item(itemId, text, title));
	};
	this.list_items = function () {
		var array = [];
		var i, length, obj, $ele;

		if ($.isEmptyObject(this.items))
			return;

		length = this.items.length;
		for (i = 0; i < length; i++) {
			obj = this.items[i];

			$ele = $('<li>', {id: obj.id}).text(obj.text);
			if ('title' in obj) $ele.attr('title', obj.title);

			if (obj instanceof Item) {
				$ele.addClass('post-item');
			} else {
				$ele.addClass('post-submenu');

				$ele.prepend(obj.list_items());
				$ele.append($('<span>', {class: 'post-menu-arrow'}).text('»'));
			}

			array.push($ele);
		}

		return $('<ul>').append(array);
	};
	this.add_submenu = function (menuId, text) {
		var ele = new List(menuId, text);
		this.items.push(ele);
		return ele;
	};
	this.get_submenu = function (menuId) {
		for (var i = 0; i < this.items.length; i++) {
			if ((this.items[i] instanceof Item) || this.items[i].id != menuId) continue;
			return this.items[i];
		}
	};
};

var Item = function (itemId, text, title) {
	this.id = itemId;
	this.text = text;

	// optional
	if (typeof title != 'undefined') this.title = title;
};

function isTransparentColor(value) {
	return !value || value === 'transparent' || value === 'rgba(0, 0, 0, 0)' || value === 'rgba(0,0,0,0)';
}

function cssVariableValue(node, name) {
	while (node && node.nodeType === 1) {
		var value = window.getComputedStyle(node).getPropertyValue(name);
		if (value && $.trim(value)) {
			return $.trim(value);
		}
		node = node.parentElement;
	}

	var rootValue = window.getComputedStyle(document.documentElement).getPropertyValue(name);
	return rootValue ? $.trim(rootValue) : '';
}

function sampleReplyBackground($context) {
	var $scope = $context && $context.length ? $context.closest('.thread') : $();
	var $reply = $scope.find('.post.reply:visible').first();

	if (!$reply.length) {
		$reply = $('.post.reply:visible').first();
	}

	if (!$reply.length) {
		return '';
	}

	var sampled = $reply.css('background-color');
	return isTransparentColor(sampled) ? '' : sampled;
}

function resolveMenuBackground($trigger, $post) {
	var sampled = '';

	if ($post && $post.length) {
		sampled = $post.css('background-color');
		if (!isTransparentColor(sampled) && !$post.hasClass('op')) {
			return sampled;
		}
	}

	sampled = sampleReplyBackground($post);
	if (sampled) {
		return sampled;
	}

	var triggerNode = $trigger && $trigger.length ? $trigger[0] : null;
	var themedFallback = cssVariableValue(triggerNode || document.body, '--fg-primary');
	if (themedFallback) {
		return themedFallback;
	}

	return '';
}

function buildMenu(e) {
	var pos = $(e.target).offset();
	var i, length;
	var $menu = $('#post-menu-root');
	var $target = $(e.target);
	var $post = $target.closest('.post.reply, .post.op, .post');
	var menuBackground = '';

	if (!$menu.length) {
		$menu = $('<div id="post-menu-root" class="post-menu hidden" hidden></div>').appendTo('body');
	}

	if (!$post.length && e.target.dataset.postTarget) {
		$post = $('#' + e.target.dataset.postTarget).closest('.post.reply, .post.op, .post');
	}

	$menu.empty().append(mainMenu.list_items());
	menuBackground = resolveMenuBackground($target, $post);
	$menu.css('--post-menu-bg-local', menuBackground);
	$menu.children('ul').css('background-color', menuBackground);

	//  execute registered click handlers
	length = onclick_callbacks.length;
	for (i = 0; i < length; i++) {
		onclick_callbacks[i](e, $menu);
	}

	//  set menu position and append to page
	$menu.css({top: pos.top, left: pos.left + 20}).removeClass('hidden').prop('hidden', false);
}

function addButton(post) {
	var $ele = $(post);

	if ($ele.find('> p.intro > .thread-top-controls > .post-btn, > p.intro > .post-btn').length) {
		return;
	}
}


/* * * * * * * * * *
    Public methods
 * * * * * * * * * */
var Menu = {};
var mainMenu = new List();
var onclick_callbacks = [];

Menu.onclick = function (fnc) {
	onclick_callbacks.push(fnc);
};

Menu.add_item = function (itemId, text, title) {
	mainMenu.add_item(itemId, text, title);
};

Menu.add_submenu = function (menuId, text) {
	return mainMenu.add_submenu(menuId, text);
};

Menu.get_submenu = function (id) {
	return mainMenu.get_submenu(id);
};

window.Menu = Menu;


/* * * * * * * *
    Initialize
 * * * * * * * */

/*  Add buttons
 */
$('.reply:not(.hidden), .thread>.op').each(function () {
	addButton(this);
 });

 /*  event handlers
  */
$(document).on('click', '.post-btn', function (e) {
	e.preventDefault();
	var post = e.target.dataset.postTarget ? document.getElementById(e.target.dataset.postTarget) : $(e.target).closest('.post')[0];
	if (!post) {
		return;
	}
	$('#post-menu-root').empty().addClass('hidden').prop('hidden', true);

	if ($(e.target).hasClass('post-btn-open')) {
		$('.post-btn-open').removeClass('post-btn-open');
	} else {
		//  close previous button
		$('.post-btn-open').removeClass('post-btn-open');
		$(post).find('.post-btn').addClass('post-btn-open');

		buildMenu(e);
	}
});

$(document).on('click', function (e){
	if ($(e.target).hasClass('post-btn') || $(e.target).hasClass('post-submenu'))
		return;

	$('#post-menu-root').empty().addClass('hidden').prop('hidden', true);
	$('.post-btn-open').removeClass('post-btn-open');
});

// on new posts
$(document).on('new_post', function (e, post) {
	addButton(post);
});

$(document).trigger('menu_ready');
});
/* End js/post-menu.js */

/* Begin js/post-filter.js */
if (active_page === 'thread' || active_page === 'index' || active_page === 'catalog' || active_page === 'ukko') {
	$(document).on('menu_ready', function () {
		'use strict';
		var Menu = window.Menu;
		if (!Menu || Menu.__postFilterMenuInstalled) {
			return;
		}
		Menu.__postFilterMenuInstalled = true;
		
		// returns blacklist object from storage
		function getList() {
			return JSON.parse(localStorage.postFilter);
		}

		// stores blacklist into storage and reruns the filter
		function setList(blacklist) {
			localStorage.postFilter = JSON.stringify(blacklist);
			$(document).trigger('filter_page');
		}

		// unit: seconds
		function timestamp() {
			return Math.floor((new Date()).getTime() / 1000);
		}

		function initList(list, boardId, threadId) {
			if (typeof list.postFilter[boardId] == 'undefined') {
				list.postFilter[boardId] = {};
				list.nextPurge[boardId] = {};
			}
			if (typeof list.postFilter[boardId][threadId] == 'undefined') {
				list.postFilter[boardId][threadId] = [];
			}
			list.nextPurge[boardId][threadId] = {timestamp: timestamp(), interval: 86400};  // 86400 seconds == 1 day
		}

		function addFilter(type, value, useRegex) {
			var list = getList();
			var filter = list.generalFilter;
			var obj = {
				type: type,
				value: value,
				regex: useRegex
			};

			for (var i=0; i<filter.length; i++) {
				if (filter[i].type == type && filter[i].value == value && filter[i].regex == useRegex)
					return;
			}

			filter.push(obj);
			setList(list);
			drawFilterList();
		}

		function removeFilter(type, value, useRegex) {
			var list = getList();
			var filter = list.generalFilter;

			for (var i=0; i<filter.length; i++) {
				if (filter[i].type == type && filter[i].value == value && filter[i].regex == useRegex) {
					filter.splice(i, 1);
					break;
				}
			}

			setList(list);
			drawFilterList();
		}

		function nameSpanToString(el) {
			var s = ''; 

			$.each($(el).contents(), function(k,v) {
				if (v.nodeName === 'IMG')
					s=s+$(v).attr('alt')
				
				if (v.nodeName === '#text')
					s=s+v.nodeValue
			});
			return s.trim();
		}

		var blacklist = {
			add: {
				post: function (boardId, threadId, postId, hideReplies) {
					var list = getList();
					var filter = list.postFilter;

					initList(list, boardId, threadId);

					for (var i in filter[boardId][threadId]) {
						if (filter[boardId][threadId][i].post == postId) return;
					}
					filter[boardId][threadId].push({
						post: postId,
						hideReplies: hideReplies
					});
					setList(list);
				},
				uid: function (boardId, threadId, uniqueId, hideReplies) {
					var list = getList();
					var filter = list.postFilter;

					initList(list, boardId, threadId);

					for (var i in filter[boardId][threadId]) {
						if (filter[boardId][threadId][i].uid == uniqueId) return;
					}
					filter[boardId][threadId].push({
						uid: uniqueId,
						hideReplies: hideReplies
					});
					setList(list);
				}
			},
			remove: {
				post: function (boardId, threadId, postId) {
					var list = getList();
					var filter = list.postFilter;

					// thread already pruned
					if (typeof filter[boardId] == 'undefined' || typeof filter[boardId][threadId] == 'undefined')
						return;

					for (var i=0; i<filter[boardId][threadId].length; i++) {
						if (filter[boardId][threadId][i].post == postId) {
							filter[boardId][threadId].splice(i, 1);
							break;
						}
					}

					if ($.isEmptyObject(filter[boardId][threadId])) {
						delete filter[boardId][threadId];
						delete list.nextPurge[boardId][threadId];

						if ($.isEmptyObject(filter[boardId])) {
							delete filter[boardId];
							delete list.nextPurge[boardId];
						}
					}
					setList(list);
				},
				uid: function (boardId, threadId, uniqueId) {
					var list = getList();
					var filter = list.postFilter;

					// thread already pruned
					if (typeof filter[boardId] == 'undefined' || typeof filter[boardId][threadId] == 'undefined')
						return;

					for (var i=0; i<filter[boardId][threadId].length; i++) {
						if (filter[boardId][threadId][i].uid == uniqueId) {
							filter[boardId][threadId].splice(i, 1);
							break;
						}
					}

					if ($.isEmptyObject(filter[boardId][threadId])) {
						delete filter[boardId][threadId];
						delete list.nextPurge[boardId][threadId];

						if ($.isEmptyObject(filter[boardId])) {
							delete filter[boardId];
							delete list.nextPurge[boardId];
						}
					}
					setList(list);
				}
			}
		};

		/* 
		 *  hide/show the specified thread/post
		 */
		function hide(ele) {
			var $ele = $(ele);

			if ($(ele).data('hidden'))
				return;

			$(ele).data('hidden', true);
			if ($ele.hasClass('op')) {
				$ele.parent().addClass('thread-filter-hidden');
				$ele.parent().find('.body, .files, .video-container').not($ele.children('.reply').children()).hide();

				// hide thread replies on index view
				if (active_page == 'index' || active_page == 'ukko') $ele.parent().find('.omitted, .reply:not(.hidden), post_no, .mentioned, br').hide();
			} else {
				// normal posts
				$ele.children('.body, .files, .video-container').hide();
			}
		}
		function show(ele) {
			var $ele = $(ele);

			$(ele).data('hidden', false);
			if ($ele.hasClass('op')) {
				$ele.parent().removeClass('thread-filter-hidden');
				$ele.parent().find('.body, .files, .video-container').show();
				if (active_page == 'index') $ele.parent().find('.omitted, .reply:not(.hidden), post_no, .mentioned, br').show();
			} else {
				// normal posts
				$ele.children('.body, .files, .video-container').show();
			}
		}

		/* 
		 *  create filter menu when the button is clicked
		 */
		function initPostMenu(pageData) {
			var submenu;
			Menu.add_item('filter-menu-hide', _('Hide post'));
			Menu.add_item('filter-menu-hide-plus', _('Hide post +'), _('Hide post and all replies'));
			Menu.add_item('filter-menu-unhide', _('Unhide post'));

			submenu = Menu.add_submenu('filter-menu-add', _('Add filter'));
				submenu.add_item('filter-add-id', _('ID'));
				submenu.add_item('filter-add-id-plus', _('ID +'), _('Hide ID and all replies'));
				submenu.add_item('filter-add-name', _('Name'));
				submenu.add_item('filter-add-trip', _('Tripcode'));
				submenu.add_item('filter-add-flag', _('Flag'));

			submenu = Menu.add_submenu('filter-menu-remove', _('Remove filter'));
				submenu.add_item('filter-remove-id', _('ID'));
				submenu.add_item('filter-remove-name', _('Name'));
				submenu.add_item('filter-remove-trip', _('Tripcode'));

			Menu.onclick(function (e, $buffer) {
				var ele = e.target.dataset.postTarget
					? document.getElementById(e.target.dataset.postTarget)
					: $(e.target).closest('.post')[0];
				var $ele = $(ele);
				var $thread = $ele.closest('.thread');

				var threadId = ($thread.attr('id') || '').replace('thread_', '');
				var boardId = $thread.data('board');
				var postId = $ele.find('.post_no').not('[id]').text();
				if (pageData.hasUID) {
					var postUid = $ele.find('.poster_id').text();
				}

				var postName;
				var postTrip = '';
				if (!pageData.forcedAnon) {
					postName = (typeof $ele.find('.name').contents()[0] == 'undefined') ? '' : nameSpanToString($ele.find('.name')[0]);
					postTrip = $ele.find('.trip').text();
				}
				var postFlag = '';
				if ($ele.find('.flag').length) {
					postFlag = $ele.find('.flag').first().attr('title') || '';
				}

				/*  display logic and bind click handlers
				 */

				 // unhide button
				if ($ele.data('hidden')) {
					$buffer.find('#filter-menu-unhide').click(function () {
						//  if hidden due to post id, remove it from blacklist
						//  otherwise just show this post
						blacklist.remove.post(boardId, threadId, postId);
						show(ele);
					});
					$buffer.find('#filter-menu-hide').addClass('hidden');
					$buffer.find('#filter-menu-hide-plus').addClass('hidden');
				} else {
					$buffer.find('#filter-menu-unhide').addClass('hidden');
					$buffer.find('#filter-menu-hide').click(function () {
						if ($ele.hasClass('op')) {
							var threadHideLink = $ele.find('p.intro .hide-thread-link').first();
							if (threadHideLink.length) {
								threadHideLink.click();
								return;
							}
						}
						blacklist.add.post(boardId, threadId, postId, false);
					});
					$buffer.find('#filter-menu-hide-plus').click(function () {
						if ($ele.hasClass('op')) {
							var threadHideLink = $ele.find('p.intro .hide-thread-link').first();
							if (threadHideLink.length) {
								threadHideLink.click();
								return;
							}
						}
						blacklist.add.post(boardId, threadId, postId, true);
					});
				}

				if ($ele.data('hiddenByPost')) {
					$buffer.find('#filter-menu-hide-plus').addClass('hidden');
				}

				// UID
				if (pageData.hasUID && !$ele.data('hiddenByUid')) {
					$buffer.find('#filter-add-id').click(function () {
						blacklist.add.uid(boardId, threadId, postUid, false);
					});
					$buffer.find('#filter-add-id-plus').click(function () {
						blacklist.add.uid(boardId, threadId, postUid, true);
					});

					$buffer.find('#filter-remove-id').addClass('hidden');
				} else if (pageData.hasUID) {
					$buffer.find('#filter-remove-id').click(function () {
						blacklist.remove.uid(boardId, threadId, postUid);
					});

					$buffer.find('#filter-add-id').addClass('hidden');
					$buffer.find('#filter-add-id-plus').addClass('hidden');
				} else {
					// board doesn't use UID
					$buffer.find('#filter-add-id').addClass('hidden');
					$buffer.find('#filter-add-id-plus').addClass('hidden');
					$buffer.find('#filter-remove-id').addClass('hidden');
				}

				//  name
				if (!pageData.forcedAnon && !$ele.data('hiddenByName')) {
					$buffer.find('#filter-add-name').click(function () {
						addFilter('name', postName, false);
					});

					$buffer.find('#filter-remove-name').addClass('hidden');
				} else if (!pageData.forcedAnon) {
					$buffer.find('#filter-remove-name').click(function () {
						removeFilter('name', postName, false);
					});

					$buffer.find('#filter-add-name').addClass('hidden');
				} else {
					// board has forced anon
					$buffer.find('#filter-remove-name').addClass('hidden');
					$buffer.find('#filter-add-name').addClass('hidden');
				}

				//  tripcode
				if (!pageData.forcedAnon && !$ele.data('hiddenByTrip') && postTrip !== '') {
					$buffer.find('#filter-add-trip').click(function () {
						addFilter('trip', postTrip, false);
					});

					$buffer.find('#filter-remove-trip').addClass('hidden');
				} else if (!pageData.forcedAnon && postTrip !== '') {
					$buffer.find('#filter-remove-trip').click(function () {
						removeFilter('trip', postTrip, false);
					});

					$buffer.find('#filter-add-trip').addClass('hidden');
				} else {
					// board has forced anon
					$buffer.find('#filter-remove-trip').addClass('hidden');
					$buffer.find('#filter-add-trip').addClass('hidden');
				}

				//  flag
				if (postFlag !== '') {
					if ($ele.data('hiddenByFlag')) {
						$buffer.find('#filter-add-flag')
							.text(_('Unfilter flag'))
							.click(function () {
								removeFilter('flag', postFlag, false);
							});
					} else {
						$buffer.find('#filter-add-flag').click(function () {
							addFilter('flag', postFlag, false);
						});
					}
				} else {
					$buffer.find('#filter-add-flag').addClass('hidden');
				}

				/*  hide sub menus if all items are hidden
				 */
				if (!$buffer.find('#filter-menu-remove > ul').children().not('.hidden').length) {
					$buffer.find('#filter-menu-remove').addClass('hidden');
				}
				if (!$buffer.find('#filter-menu-add > ul').children().not('.hidden').length) {
					$buffer.find('#filter-menu-add').addClass('hidden');
				}
			});
		}

		/* 
		 *  hide/unhide thread on index view
		 */
		function quickToggle(ele, threadId, pageData) {
			if ($(ele).hasClass('op')) {
				var link = $(ele).find('p.intro .hide-thread-link').first();
				if (link.length) {
					link.html('[' + ($(ele).data('hidden') ? '+' : '&ndash;') + ']');
				}
			}
		}

		/*
		 *  determine whether the reply post should be hidden
		 *   - applies to all posts on page load or filtering rule change
		 *   - apply to new posts on thread updates
		 *   - must explicitly set the state of each attributes because filter will reapply to all posts after filtering rule change
		 */
		function filter(post, threadId, pageData) {
			var $post = $(post);

			var list = getList();
			var postId = $post.find('.post_no').not('[id]').text();
			var name, trip, uid, subject, comment, flag;
			var i, length, array, rule, pattern;  // temp variables

			var boardId	      = $post.data('board');
			if (!boardId) boardId = $post.parents('.thread').data('board');

			var localList   = pageData.localList;
			var noReplyList = pageData.noReplyList;
			var hasUID      = pageData.hasUID;
			var forcedAnon  = pageData.forcedAnon;

			var hasTrip = ($post.find('.trip').length > 0);
			var hasSub = ($post.find('.subject').length > 0);
			var hasFlag = ($post.find('.flag').length > 0);

			$post.data('hidden', false);
			$post.data('hiddenByUid', false);
			$post.data('hiddenByPost', false);
			$post.data('hiddenByName', false);
			$post.data('hiddenByTrip', false);
			$post.data('hiddenBySubject', false);
			$post.data('hiddenByComment', false);
			$post.data('hiddenByFlag', false);

			// add post with matched UID to localList
			if (hasUID &&
				typeof list.postFilter[boardId] != 'undefined' &&
				typeof list.postFilter[boardId][threadId] != 'undefined') {
				uid = $post.find('.poster_id').text();
				array = list.postFilter[boardId][threadId];

				for (i=0; i<array.length; i++) {
					if (array[i].uid == uid) {
						$post.data('hiddenByUid', true);
						localList.push(postId);
						if (array[i].hideReplies) noReplyList.push(postId);
						break;
					}
				}
			}

			// match localList
			if (localList.length) {
				if ($.inArray(postId, localList) != -1) {
					if ($post.data('hiddenByUid') !== true) $post.data('hiddenByPost', true);
					hide(post);
				}
			}

			// matches generalFilter
			if (!forcedAnon)
				name = (typeof $post.find('.name').contents()[0] == 'undefined') ? '' : nameSpanToString($post.find('.name')[0]);
			if (!forcedAnon && hasTrip)
				trip = $post.find('.trip').text();
			if (hasSub)
				subject = $post.find('.subject').text();

			array = $post.find('.body').contents().filter(function () {if ($(this).text() !== '') return true;}).toArray();
			array = $.map(array, function (ele) {
				return $(ele).text().trim();
			});
			comment = array.join(' ');

			if (hasFlag)
				flag = $post.find('.flag').attr('title')

			for (i = 0, length = list.generalFilter.length; i < length; i++) {
				rule = list.generalFilter[i];

				if (rule.regex) {
					pattern = new RegExp(rule.value);
					switch (rule.type) {
						case 'name':
							if (!forcedAnon && pattern.test(name)) {
								$post.data('hiddenByName', true);
								hide(post);
							}
							break;
						case 'trip':
							if (!forcedAnon && hasTrip && pattern.test(trip)) {
								$post.data('hiddenByTrip', true);
								hide(post);
							}
							break;
						case 'sub':
							if (hasSub && pattern.test(subject)) {
								$post.data('hiddenBySubject', true);
								hide(post);
							}
							break;
						case 'com':
							if (pattern.test(comment)) {
								$post.data('hiddenByComment', true);
								hide(post);
							}
							break;
						case 'flag':
							if (hasFlag && pattern.test(flag)) {
								$post.data('hiddenByFlag', true);
								hide(post);
							}
							break;
					}
				} else {
					switch (rule.type) {
						case 'name':
							if (!forcedAnon && rule.value == name) {
								$post.data('hiddenByName', true);
								hide(post);
							}
							break;
						case 'trip':
							if (!forcedAnon && hasTrip && rule.value == trip) {
								$post.data('hiddenByTrip', true);
								hide(post);
							}
							break;
						case 'sub':
							pattern = new RegExp('\\b'+ rule.value+ '\\b');
							if (hasSub && pattern.test(subject)) {
								$post.data('hiddenBySubject', true);
								hide(post);
							}
							break;
						case 'com':
							pattern = new RegExp('\\b'+ rule.value+ '\\b');
							if (pattern.test(comment)) {
								$post.data('hiddenByComment', true);
								hide(post);
							}
							break;
						case 'flag':
							pattern = new RegExp('\\b'+ rule.value+ '\\b');
							if (hasFlag && pattern.test(flag)) {
								$post.data('hiddenByFlag', true);
								hide(post);
							}
							break;
					}
				}
			}

			// check for link to filtered posts
			$post.find('.body a').not('[rel="nofollow"]').each(function () {
				var replyId = $(this).text().match(/^>>(\d+)$/);

				if (!replyId)
					return;

				replyId = replyId[1];
				if ($.inArray(replyId, noReplyList) != -1) {
					hide(post);
				}
			});

			// post didn't match any filters
			if (!$post.data('hidden')) {
				show(post);
			}
		}

		/*  (re)runs the filter on the entire page
		 */
		 function filterPage(pageData) {
			var list = getList();

			if (active_page != 'catalog') {

				// empty the local and no-reply list
				pageData.localList = [];
				pageData.noReplyList = [];

				$('.thread').each(function () {
					var $thread = $(this);
					// disregard the hidden threads constructed by post-hover.js
					if ($thread.css('display') == 'none')
						return;

					var threadId = $thread.attr('id').replace('thread_', '');
					var boardId = $thread.data('board');
					var op = $thread.children('.op')[0];
					var i, array;  // temp variables

					// add posts to localList and noReplyList
					if (typeof list.postFilter[boardId] != 'undefined' && typeof list.postFilter[boardId][threadId] != 'undefined') {
						array = list.postFilter[boardId][threadId];
						for (i=0; i<array.length; i++) {
							if ( typeof array[i].post == 'undefined')
								continue;

							pageData.localList.push(array[i].post);
							if (array[i].hideReplies) pageData.noReplyList.push(array[i].post);
						}
					}
					// run filter on OP
					filter(op, threadId, pageData);
					quickToggle(op, threadId, pageData);

					// iterate filter over each post
					if (!$(op).data('hidden') || active_page == 'thread') {
						$thread.find('.reply').not('.hidden').each(function () {
							filter(this, threadId, pageData);
						});
					}

				});
			} else {
				var postFilter = list.postFilter[pageData.boardId];
				var $collection = $('.mix');

				if ($.isEmptyObject(postFilter))
					return;

				// for each thread that has filtering rules
				// check if filter contains thread OP and remove the thread from catalog
				$.each(postFilter, function (key, thread) {
					var threadId = key;
					$.each(thread, function () {
						if (this.post == threadId) {
							$collection.filter('[data-id='+ threadId +']').remove();
						}
					});
				});
			}
		 }

		function initStyle() {
			var $ele, cssStyle, cssString;

			$ele = $('<div>').addClass('post reply').hide().appendTo('body');
			cssStyle = $ele.css(['background-color', 'border-color']);
			cssStyle.hoverBg = $('body').css('background-color');
			$ele.remove();

			cssString = '\n/*** Generated by post-filter ***/\n' +
				'#filter-control input[type=text] {width: 130px;}' +
				'#filter-control input[type=checkbox] {vertical-align: middle;}' +
				'#filter-control #clear {float: right;}\n' +
				'#filter-container {margin-top: 20px; border: 1px solid; height: 270px; overflow: auto;}\n' +
				'#filter-list {width: 100%; border-collapse: collapse;}\n' +
				'#filter-list th {text-align: center; height: 20px; font-size: 14px; border-bottom: 1px solid;}\n' +
				'#filter-list th:nth-child(1) {text-align: center; width: 70px;}\n' +
				'#filter-list th:nth-child(2) {text-align: left;}\n' +
				'#filter-list th:nth-child(3) {text-align: center; width: 58px;}\n' +
				'#filter-list tr:not(#header) {height: 22px;}\n' +
				'#filter-list tr:nth-child(even) {background-color:rgba(255, 255, 255, 0.5);}\n' +
				'#filter-list td:nth-child(1) {text-align: center; width: 70px;}\n' +
				'#filter-list td:nth-child(3) {text-align: center; width: 58px;}\n' +
				'#confirm {text-align: right; margin-bottom: -18px; padding-top: 2px; font-size: 14px; color: #FF0000;}';

			if (!$('style.generated-css').length) $('<style class="generated-css">').appendTo('head');
			$('style.generated-css').html($('style.generated-css').html() + cssString);
		}

		function drawFilterList() {
			var list = getList().generalFilter;
			var $ele = $('#filter-list');
			var $row, i, length, obj, val;

			var typeName = {
				name: 'name',
				trip: 'tripcode',
				sub: 'subject',
				com: 'comment',
				flag: 'flag'
			};

			$ele.empty();

			$ele.append('<tr id="header"><th>Type</th><th>Content</th><th>Remove</th></tr>');
			for (i = 0, length = list.length; i < length; i++) {
				obj = list[i];

				// display formatting
				val = (obj.regex) ? '/'+ obj.value +'/' : obj.value;

				$row = $('<tr>');
				$row.append(
					'<td>'+ typeName[obj.type] +'</td>',
					'<td>'+ val +'</td>',
					$('<td>').append(
						$('<a>').html('X')
							.addClass('del-btn')
							.attr('href', '#')
							.data('type', obj.type)
							.data('val', obj.value)
							.data('useRegex', obj.regex)
					)
				);
				$ele.append($row);
			}
		}

		function initOptionsPanel() {
			if (window.Options && !Options.get_tab('filter')) {
				Options.add_tab('filter', 'list', _('Filters'));
				Options.extend_tab('filter',
					'<div id="filter-control">' +
						'<select>' +
							'<option value="name">'+_('Name')+'</option>' +
							'<option value="trip">'+_('Tripcode')+'</option>' +
							'<option value="sub">'+_('Subject')+'</option>' +
							'<option value="com">'+_('Comment')+'</option>' +
							'<option value="flag">'+_('Flag')+'</option>' +
						'</select>' +
						'<input type="text">' +
						'<input type="checkbox">' +
						'regex ' +
						'<button id="set-filter">'+_('Add')+'</button>' +
						'<button id="clear">'+_('Clear all filters')+'</button>' +
						'<div id="confirm" class="hidden">' +
							_('This will clear all filtering rules including hidden posts.')+' <a id="confirm-y" href="#">'+_('yes')+'</a> | <a id="confirm-n" href="#">'+_('no')+'</a>' +
						'</div>' +
					'</div>' +
					'<div id="filter-container"><table id="filter-list"></table></div>'
				);
				drawFilterList();

				// control buttons
				$('#filter-control').on('click', '#set-filter', function () {
					var type = $('#filter-control select option:selected').val();
					var value = $('#filter-control input[type=text]').val();
					var useRegex = $('#filter-control input[type=checkbox]').prop('checked');

					//clear the input form
					$('#filter-control input[type=text]').val('');

					addFilter(type, value, useRegex);
					drawFilterList();
				});
				$('#filter-control').on('click', '#clear', function () {
					$('#filter-control #clear').addClass('hidden');
					$('#filter-control #confirm').removeClass('hidden');
				});
				$('#filter-control').on('click', '#confirm-y', function (e) {
					e.preventDefault();

					$('#filter-control #clear').removeClass('hidden');
					$('#filter-control #confirm').addClass('hidden');
					setList({
						generalFilter: [],
						postFilter: {},
						nextPurge: {},
						lastPurge: timestamp()
					});
					$(document).trigger('clear_hidden_threads');
					drawFilterList();
				});
				$('#filter-control').on('click', '#confirm-n', function (e) {
					e.preventDefault();

					$('#filter-control #clear').removeClass('hidden');
					$('#filter-control #confirm').addClass('hidden');
				});


				// remove button
				$('#filter-list').on('click', '.del-btn', function (e) {
					e.preventDefault();

					var $ele = $(e.target);
					var type = $ele.data('type');
					var val = $ele.data('val');
					var useRegex = $ele.data('useRegex');

					removeFilter(type, val, useRegex);
				});
			}
		}

		/* 
		 *  clear out pruned threads
		 */
		function purge() {
			var list = getList();
			var board, thread, boardId, threadId;
			var deferred;
			var requestArray = [];

			var successHandler = function (boardId, threadId) {
				return function () {
					// thread still alive, keep it in the list and increase the time between checks.
					var list = getList();
					var thread = list.nextPurge[boardId][threadId];

					thread.timestamp = timestamp();
					thread.interval = Math.floor(thread.interval * 1.5);
					setList(list);
				};
			};
			var errorHandler = function (boardId, threadId) {
				return function (xhr) {
					if (xhr.status == 404) {
						var list = getList();

						delete list.nextPurge[boardId][threadId];
						delete list.postFilter[boardId][threadId];
						if ($.isEmptyObject(list.nextPurge[boardId])) delete list.nextPurge[boardId];
						if ($.isEmptyObject(list.postFilter[boardId])) delete list.postFilter[boardId];
						setList(list);
					}
				};
			};

			if ((timestamp() - list.lastPurge) < 86400)  // less than 1 day
				return;
			
			for (boardId in list.nextPurge) {
				board = list.nextPurge[boardId];
				for (threadId in board) {
					thread = board[threadId];
					if (timestamp() > (thread.timestamp + thread.interval)) {
						// check if thread is pruned
						deferred = $.ajax({
							cache: false,
							url: '/'+ boardId +'/res/'+ threadId +'.json',
							success: successHandler(boardId, threadId),
							error: errorHandler(boardId, threadId)
						});
						requestArray.push(deferred);
					}
				}
			}

			// when all requests complete
			$.when.apply($, requestArray).always(function () {
				var list = getList();
				list.lastPurge = timestamp();
				setList(list);
			});
		}

		function init() {
			if (typeof localStorage.postFilter === 'undefined') {
				localStorage.postFilter = JSON.stringify({
					generalFilter: [],
					postFilter: {},
					nextPurge: {},
					lastPurge: timestamp()
				});
			}

			var pageData = {
				boardId: board_name,  // get the id from the global variable
				localList: [],  // all the blacklisted post IDs or UIDs that apply to the current page
				noReplyList: [],  // any posts that replies to the contents of this list shall be hidden
				hasUID: (document.getElementsByClassName('poster_id').length > 0),
				forcedAnon: ($('th:contains(Name)').length === 0)  // tests by looking for the Name label on the reply form
			};

			initStyle();
			initOptionsPanel();
			initPostMenu(pageData);
			filterPage(pageData);

			// on new posts
			$(document).on('new_post', function (e, post) {
				var threadId;
				var $post = $(post);

				if ($post.hasClass('reply')) {
					threadId = $post.parents('.thread').attr('id').replace('thread_', '');
				} else if ($post.hasClass('op')) {
					threadId = $post.parents('.thread').attr('id').replace('thread_', '');
				} else {
					threadId = ($post.attr('id') || '').replace('thread_', '');
					post = $post.children('.op')[0] || post;
				}

				filter(post, threadId, pageData);
				quickToggle(post, threadId, pageData);
			});

			$(document).on('filter_page', function () {
				filterPage(pageData);
			});

			// shift+click on catalog to hide thread
			if (active_page == 'catalog') {
				$(document).on('click', '.mix', function(e) {
					if (e.shiftKey) {
						var threadId = $(this).data('id').toString();
						var postId = threadId;
						blacklist.add.post(pageData.boardId, threadId, postId, false);
					}
				});
			}

			// clear out the old threads
			purge();
		}
		init();
	});
	
	if (typeof window.Menu !== "undefined") {
		$(document).trigger('menu_ready');
	}
}
