auto_reload_enabled = true; // for watch.js to interop

$(document).ready(function(){
	var runtime = window.EirinchanRuntime || {};
	var livePageCookieName = 'live_page_auto_update';
	var parseFragmentDocument = (function() {
		var parser = typeof DOMParser !== 'undefined' ? new DOMParser() : null;
		return function(markup) {
			return parser ? parser.parseFromString(markup, 'text/html') : null;
		};
	})();
	var dispatchNewPost = function(post) {
		if (!post) {
			return;
		}

		if (window.EirinchanFrontend && typeof window.EirinchanFrontend.dispatchNewPost === 'function') {
			window.EirinchanFrontend.dispatchNewPost(post);
		} else {
			$(document).trigger('new_post', post);
		}
	};
	var queueNextPoll = function(delay) {
		if ($('#auto_update_status').is(':checked')) {
			poll_interval_delay = delay;
			auto_update(poll_interval_delay);
		}
	};
	var readLivePageCookie = function() {
		var value = runtime.readCookie ? runtime.readCookie(livePageCookieName, '1') : null;
		if (value === null) {
			var match = document.cookie.match(new RegExp('(?:^|; )' + livePageCookieName + '=([^;]*)'));
			if (!match) {
				return true;
			}

			value = decodeURIComponent(match[1]);
		}

		return value !== '0';
	};

	var writeLivePageCookie = function(enabled) {
		if (runtime.writeCookie) {
			runtime.writeCookie(livePageCookieName, enabled ? '1' : '0', {
				path: '/',
				maxAge: 60 * 60 * 24 * 365,
				sameSite: 'lax'
			});
			return;
		}

		document.cookie =
			livePageCookieName + '=' + encodeURIComponent(enabled ? '1' : '0') +
			'; path=/; max-age=' + (60 * 60 * 24 * 365);
	};

	var is_thread_page = $('div.banner').length != 0 && $(".post.op").length == 1;
	var is_catalog_page = $('body').hasClass('active-catalog') && $('#Grid').length == 1;
	var is_board_page = $('body').hasClass('active-index') && !is_thread_page && !is_catalog_page && $('#board-refresh-target').length == 1;
	var active_poll_request = null;

	if(!is_thread_page && !is_catalog_page && !is_board_page)
		return;

	if ($('#updater').length === 0)
		return;
	
	var countdown_interval;

	// Grab the settings
	var settings = new script_settings('auto-reload');
	var poll_interval_mindelay        = settings.get('min_delay_bottom', 5000);
	var poll_interval_maxdelay        = settings.get('max_delay', 600000);
	var poll_interval_errordelay      = settings.get('error_delay', 30000);

	if (is_board_page) {
		poll_interval_mindelay = 5000;
		poll_interval_maxdelay = 5000;
		poll_interval_errordelay = 5000;
	}

	// number of ms to wait before reloading
	var poll_interval_delay = poll_interval_mindelay;
	var poll_current_time = poll_interval_delay;

	var end_of_page = false;

        var new_posts = 0;
	var first_new_post = null;
	
	var title = document.title;

	var numeric_suffix = function(value) {
		var match = (value || '').toString().match(/(\d+)$/);
		return match ? parseInt(match[1], 10) : 0;
	};

	if (typeof update_title == "undefined") {
	   var update_title = function() { 
	   	if (new_posts) {
	   		document.title = "("+new_posts+") "+title;
	   	} else {
	   		document.title = title;
	   	}
	   };
	}

	if (typeof add_title_collector != "undefined")
	add_title_collector(function(){
	  return new_posts;
	});

	var window_active = true;
	$(window).focus(function() {
		window_active = true;
		if (!is_thread_page) {
			new_posts = 0;
			update_title();
		}
		recheck_activated();

		// Reset the delay if needed
		if(settings.get('reset_focus', true)) {
			poll_interval_delay = poll_interval_mindelay;
		}
	});
	$(window).blur(function() {
		window_active = false;
	});
	

	$('#auto_update_status').change(function() {
		writeLivePageCookie($("#auto_update_status").is(':checked'));

		if($("#auto_update_status").is(':checked')) {
			auto_update(poll_interval_mindelay);
		} else {
			stop_auto_update();
			$('#update_secs').text("");
		}

		update_live_button_state();
	});
	

	var decrement_timer = function() {
		poll_current_time = poll_current_time - 1000;
		if (poll_current_time <= 0) {
			poll_current_time = 0;
			$('#update_secs').text("0");
			if (is_catalog_page) {
				refresh_if_changed(poll_catalog);
			} else if (is_board_page) {
				refresh_if_changed(poll_board);
			} else {
				refresh_if_changed(poll_thread);
			}
			return;
		}

		$('#update_secs').text(poll_current_time/1000);
	}

	var recheck_activated = function() {
		if (is_catalog_page) {
			return;
		}

		if (new_posts && window_active &&
			$(window).scrollTop() + $(window).height() >=
			$('div.boardlist.bottom').position().top) {

			new_posts = 0;
		}
		update_title();
		first_new_post = null;
	};
	
	// automatically updates the thread after a specified delay
	var auto_update = function(delay) {
		clearInterval(countdown_interval);

		poll_current_time = delay;		
		countdown_interval = setInterval(decrement_timer, 1000);
		$('#update_secs').text(poll_current_time/1000);
		update_live_button_state();
	}
	
	var stop_auto_update = function() {
		clearInterval(countdown_interval);
		update_live_button_state();
	}

	var update_live_button_state = function() {
		var updater = $('#updater');
		var active = $('#auto_update_status').is(':checked') && !$('#auto_update_status').is(':disabled');

		updater.toggleClass('paused', !active);
		updater.toggleClass('active', active);
	}

	var can_start_poll = function() {
		return active_poll_request === null;
	}

	var finish_poll = function() {
		active_poll_request = null;
	}

	var begin_poll = function(request) {
		active_poll_request = request;
	}
		
    	var epoch = (new Date).getTime();
    	var epochold = epoch;
    	
	var timeDiff = function (delay) {
		if((epoch-epochold) > delay) {
			epochold = epoch = (new Date).getTime();
			return true;
		}else{
			epoch = (new Date).getTime();
			return;
		}
	}
	
	var fragment_url = function() {
		var url = new URL(document.location.href);
		url.searchParams.set('fragment', '1');
		return url.toString();
	};

	var has_active_inline_video = function() {
		return Array.prototype.some.call(document.querySelectorAll('video'), function(video) {
			if (!video.offsetParent) return false;
			if (video.closest('#alert_handler')) return false;
			return !!video.controls || !video.paused;
		});
	};

	var should_defer_for_media = function() {
		return has_active_inline_video();
	};

	var fragment_md5_url = function() {
		var url = new URL(document.location.href);
		url.searchParams.set('fragment', 'md5');
		return url.toString();
	};

	var current_fragment_container = function() {
		if (is_catalog_page)
			return document.getElementById('Grid');
		if (is_board_page)
			return document.getElementById('board-refresh-target');
		if (is_thread_page)
			return document.getElementById('thread-refresh-target');
		return null;
	};

	var current_fragment_md5 = function() {
		var container = current_fragment_container();
		if (!container || !container.dataset) {
			return '';
		}

		return container.dataset.fragmentMd5 || '';
	};

	var sync_global_message = function(doc) {
		var replacement = doc && doc.querySelector ? doc.querySelector('#global-message-refresh-target') : null;
		var current = document.getElementById('global-message-refresh-target');

		if (!replacement || !current) {
			return;
		}

		current.replaceWith(replacement);
	};

	var refresh_if_changed = function(pollFn) {
		if (!can_start_poll()) {
			return false;
		}

		if (should_defer_for_media()) {
			queueNextPoll(poll_interval_mindelay);
			return false;
		}

		var localMd5 = current_fragment_md5();
		var request = $.ajax({
			url: fragment_md5_url(),
			cache: false,
			success: function(data) {
				var serverMd5 = $.trim(data || '');

				if (serverMd5 && localMd5 && serverMd5 === localMd5) {
					queueNextPoll(poll_interval_mindelay);
					return;
				}

				finish_poll();
				pollFn(false);
			},
			error: function() {
				queueNextPoll(poll_interval_errordelay);
			},
			complete: function() {
				if (active_poll_request === request) {
					finish_poll();
				}
			}
		});

		begin_poll(request);
		return false;
	};

	var sync_thread_seen = function() {
		if (!is_thread_page || typeof window.markWatchedThreadSeen !== 'function') {
			return;
		}

		var watchLink = document.querySelector('.thread[data-thread-id]');
		if (!watchLink || watchLink.dataset.watched !== 'true') {
			return;
		}

		var replyIds = Array.prototype.map.call(document.querySelectorAll('div.thread div.post[id^="reply_"]'), function(node) {
			return parseInt(node.id.replace('reply_', ''), 10);
		}).filter(function(value) {
			return !isNaN(value);
		});

		var threadId = parseInt(watchLink.dataset.threadId, 10);
		var lastSeenPostId = replyIds.length ? Math.max.apply(null, replyIds) : threadId;
		if (threadId > lastSeenPostId) lastSeenPostId = threadId;

		window.markWatchedThreadSeen(watchLink.dataset.boardUri, threadId, lastSeenPostId);
	};
	
	var poll_catalog = function(manualUpdate) {
		if (!can_start_poll()) {
			return false;
		}

		stop_auto_update();
		$('#update_secs').text("0");

		var request = $.ajax({
			url: fragment_url(),
			cache: false,
			success: function(data) {
				var new_threads = 0;
				var doc = parseFragmentDocument(data);
				var replacement = doc.querySelector('#Grid');
				var currentGrid = document.getElementById('Grid');
				var current_ids = {};
				var seen_ids = {};
				var cards_to_prepend = [];

				if (!replacement || !currentGrid) {
					$('#update_secs').text(_("Unknown error"));
					queueNextPoll(poll_interval_errordelay);
					return;
				}

				sync_global_message(doc);

				if (replacement.dataset && replacement.dataset.fragmentMd5) {
					currentGrid.dataset.fragmentMd5 = replacement.dataset.fragmentMd5;
				}

				$(currentGrid).children('.mix').each(function() {
					var id = this.getAttribute('data-id');
					if (id) {
						current_ids[id] = this;
					}
				});

				var max_current_id = Object.keys(current_ids).reduce(function(maxId, id) {
					return Math.max(maxId, numeric_suffix(id));
				}, 0);

				Array.prototype.forEach.call(replacement.querySelectorAll('.mix'), function(card) {
					var id = card.getAttribute('data-id');
					var clone = card.cloneNode(true);

					if (id) {
						seen_ids[id] = true;
					}

					if (id && current_ids[id]) {
						current_ids[id].replaceWith(clone);
						current_ids[id] = clone;
					} else {
						if (numeric_suffix(id) > max_current_id) {
							new_threads++;
						}
						cards_to_prepend.push(clone);
					}
				});

				$(currentGrid).children('.mix').each(function() {
					var id = this.getAttribute('data-id');
					if (id && !seen_ids[id]) {
						this.remove();
					}
				});

				for (var i = cards_to_prepend.length - 1; i >= 0; i--) {
					currentGrid.insertBefore(cards_to_prepend[i], currentGrid.firstChild);
				}

				if (window.bind_image_hover) {
					window.bind_image_hover(currentGrid);
				}

				if (new_threads > 0) {
					new_posts += new_threads;
					update_title();
				}

				if ($('#auto_update_status').is(':checked')) {
					queueNextPoll(poll_interval_mindelay);
				} else {
					if (new_threads > 0)
						$('#update_secs').text(fmt(_("Catalog updated with {0} new thread(s)"), [new_threads]));
					else
						$('#update_secs').text(_("No new threads found"));
				}
			},
			error: function(xhr, status_text, error_text) {
				if (status_text == "error" && error_text) {
					$('#update_secs').text("Error: "+error_text);
				} else if (status_text) {
					$('#update_secs').text(_("Error: ")+status_text);
				} else {
					$('#update_secs').text(_("Unknown error"));
				}

				queueNextPoll(poll_interval_errordelay);
			},
			complete: function() {
				finish_poll();
			}
		});
		begin_poll(request);

		return false;
	};

	var poll_board = function(manualUpdate) {
		if (!can_start_poll()) {
			return false;
		}

		stop_auto_update();
		$('#update_secs').text("0");

		var request = $.ajax({
			url: fragment_url(),
			cache: false,
			success: function(data) {
				var doc = parseFragmentDocument(data);
				var replacement = doc.querySelector('#board-refresh-target');
				var current = document.querySelector('#board-refresh-target');
				var currentThreads;
				var hiddenStateById = {};
				var loaded_posts = 0;
				var max_current_post_id = 0;

				if (!replacement || !current) {
					$('#update_secs').text(_("Unknown error"));
					queueNextPoll(poll_interval_errordelay);
					return;
				}

				sync_global_message(doc);

				currentThreads = current.querySelector('#board-threads');
				if (currentThreads) {
					Array.prototype.forEach.call(currentThreads.querySelectorAll('.post[id]'), function(node) {
						max_current_post_id = Math.max(max_current_post_id, numeric_suffix(node.id));
					});

					Array.prototype.forEach.call(currentThreads.querySelectorAll('.thread'), function(node) {
						if (!node.id) return;
						hiddenStateById[node.id] = {
							threadHidden: node.classList.contains('thread-hidden'),
							display: node.style.display || '',
							watched: node.dataset ? node.dataset.watched : null
						};
					});
				}

				Array.prototype.forEach.call(replacement.querySelectorAll('#board-threads .thread'), function(node) {
					var state = node.id ? hiddenStateById[node.id] : null;
					if (!state) return;

					if (state.threadHidden) {
						node.classList.add('thread-hidden');
					}
					if (state.display) {
						node.style.display = state.display;
					}
					if (state.watched !== null && node.dataset) {
						node.dataset.watched = state.watched;
					}
				});

				Array.prototype.forEach.call(replacement.querySelectorAll('.post[id]'), function(node) {
					if (numeric_suffix(node.id) > max_current_post_id) {
						loaded_posts++;
					}
				});

				current.replaceWith(replacement);

				$(replacement).find('.post').each(function() {
					dispatchNewPost(this);
				});

				if (typeof window.EirinchanInitExpand === 'function') {
					window.EirinchanInitExpand(replacement);
				}
				if (typeof window.bind_image_hover === 'function') {
					window.bind_image_hover(replacement);
				}
				if (typeof window.bind_inline_expanding === 'function') {
					window.bind_inline_expanding(replacement);
				}
				if (loaded_posts > 0) {
					new_posts += loaded_posts;
					update_title();
				}

				if ($('#auto_update_status').is(':checked')) {
					queueNextPoll(poll_interval_mindelay);
				} else {
					$('#update_secs').text("5");
				}
			},
			error: function(xhr, status_text, error_text) {
				if (status_text == "error" && error_text) {
					$('#update_secs').text("Error: " + error_text);
				} else if (status_text) {
					$('#update_secs').text("5");
				} else {
					$('#update_secs').text("5");
				}

				queueNextPoll(poll_interval_errordelay);
			},
			complete: function() {
				finish_poll();
			}
		});
		begin_poll(request);

		return false;
	};

	var poll_thread = function(manualUpdate) {
		if (!can_start_poll()) {
			return false;
		}

		stop_auto_update();
		$('#update_secs').text("0");
	
		var request = $.ajax({
			url: fragment_url(),
			cache: false,
			success: function(data) {
				var doc = parseFragmentDocument(data);
				var replacement = doc.querySelector('#thread-refresh-target');
				var loaded_posts = 0;	// the number of new posts loaded in this update
				var elementsToAppend = [];
				var insertedPostIds = [];
				sync_global_message(doc);
				if (replacement && replacement.dataset && replacement.dataset.fragmentMd5) {
					var currentContainer = document.getElementById('thread-refresh-target');
					if (currentContainer) {
						currentContainer.dataset.fragmentMd5 = replacement.dataset.fragmentMd5;
						currentContainer.dataset.boardPageNum = replacement.dataset.boardPageNum || '';
						currentContainer.dataset.boardPagePath = replacement.dataset.boardPagePath || '';
					}
				}
				$(replacement || data).find('div.post.reply').each(function() {
					var id = $(this).attr('id');
					if($('#' + id).length == 0) {
						if (!new_posts) {
							first_new_post = this;
						}
						new_posts++;
						loaded_posts++;
						elementsToAppend.push($(this));
						elementsToAppend.push($('<br class="clear">'));
						insertedPostIds.push(id);
					}
				});
				if (elementsToAppend.length) {
					var currentContainer = $('#thread-refresh-target');
					var lastReply = currentContainer.children('div.post.reply:last');
					var clearBreak = lastReply.next('br.clear');

					if (clearBreak.length) {
						clearBreak.after(elementsToAppend);
					} else if (lastReply.length) {
						lastReply.after(elementsToAppend);
					} else {
						currentContainer.append(elementsToAppend);
					}
				}
				recheck_activated();
				insertedPostIds.forEach(function(id){
					var inserted = document.getElementById(id);
					if (inserted) {
						if (typeof window.syncBacklinksFromPost === 'function') {
							window.syncBacklinksFromPost(inserted);
						}
						dispatchNewPost(inserted);
					}
				});

				if (replacement && replacement.dataset) {
					var boardPageNum = replacement.dataset.boardPageNum || '';
					var boardPagePath = replacement.dataset.boardPagePath || '';
					if (boardPageNum) {
						$('#thread_stats_page').text(boardPageNum);
					}
					if (boardPagePath) {
						$('#thread-return, #thread-return-top').attr('href', boardPagePath);
					}
				}
				if (typeof window.sync_thread_seen === 'function') {
					window.sync_thread_seen();
				}
				time_loaded = Date.now(); // interop with watch.js
				
				
				if ($('#auto_update_status').is(':checked')) {
					queueNextPoll(poll_interval_mindelay);
				} else {
					// Decide the message to show if auto update is disabled
					if (loaded_posts > 0)
						$('#update_secs').text(fmt(_("Thread updated with {0} new post(s)"), [loaded_posts]));
					else
						$('#update_secs').text(_("No new posts found"));
				}
			},
			error: function(xhr, status_text, error_text) {
				if (status_text == "error") {
					if (error_text == "Not Found") {
						$('#update_secs').text(_("Thread deleted or pruned"));
						$('#auto_update_status').prop('checked', false);
						$('#auto_update_status').prop('disabled', true); // disable updates if thread is deleted
						return;
					} else {
						$('#update_secs').text("Error: "+error_text);
					}
				} else if (status_text) {
					$('#update_secs').text(_("Error: ")+status_text);
				} else {
					$('#update_secs').text(_("Unknown error"));
				}
				
				// Keep trying to update
				queueNextPoll(poll_interval_errordelay);
			},
			complete: function() {
				finish_poll();
			}
		});
		begin_poll(request);
		
		return false;
	};
	
	if (is_thread_page) {
		$(window).scroll(function() {
			recheck_activated();
			
			// if the newest post is not visible
			if($(this).scrollTop() + $(this).height() <
				$('div.post:last').position().top + $('div.post:last').height()) {
				end_of_page = false;
				return;
			} else {
				if($("#auto_update_status").is(':checked') && timeDiff(poll_interval_mindelay)) {
					poll_thread(manualUpdate = true);
				}
				end_of_page = true;
			}
		});
	}

	$('#update_thread').on('click', function() {
		var checkbox = $('#auto_update_status');
		checkbox.prop('checked', !checkbox.is(':checked'));
		checkbox.trigger('change');
		return false;
	});

	$('#auto_update_status').prop('checked', readLivePageCookie());

	update_live_button_state();

	if($("#auto_update_status").is(':checked')) {
		auto_update(poll_interval_delay);
	}
});
/* End js/auto-reload.js */

/* Begin js/image-hover.js */
/* image-hover.js 
 * This script is copied almost verbatim from https://github.com/Pashe/8chanX/blob/2-0/8chan-x.user.js
 * All I did was remove the sprintf dependency and integrate it into 8chan's Options as opposed to Pashe's.
 * I also changed initHover() to also bind on new_post.
 * Thanks Pashe for using WTFPL.
 */

if (active_page === "catalog" || active_page === "thread" || active_page === "index") {
$(function(){

if (window.Options && Options.get_tab('general')) {
	Options.extend_tab("general", 
	"<fieldset><legend>Image hover</legend>"
	+ ("<label class='image-hover' id='imageHover'><input type='checkbox' /> "+_('Image hover')+"</label>")
	+ ("<label class='image-hover' id='catalogImageHover'><input type='checkbox' /> "+_('Image hover on catalog')+"</label>")
	+ ("<label class='image-hover' id='imageHoverFollowCursor'><input type='checkbox' /> "+_('Image hover should follow cursor')+"</label>")
	+ "</fieldset>");
}

$('.image-hover').on('change', function(){
	var setting = $(this).attr('id');

	localStorage[setting] = $(this).children('input').is(':checked');
});

if (typeof localStorage.imageHover === 'undefined') {
	localStorage.imageHover = 'true';
}
if (typeof localStorage.catalogImageHover === 'undefined') {
	localStorage.catalogImageHover = 'true';
}
if (typeof localStorage.imageHoverFollowCursor === 'undefined') {
	localStorage.imageHoverFollowCursor = 'true';
}

if (getSetting('imageHover')) $('#imageHover>input').prop('checked', 'checked');
if (getSetting('catalogImageHover')) $('#catalogImageHover>input').prop('checked', 'checked');
if (getSetting('imageHoverFollowCursor')) $('#imageHoverFollowCursor>input').prop('checked', 'checked');

function getFileExtension(filename) { //Pashe, WTFPL
	if (filename.match(/\.([a-z0-9]+)(&loop.*)?$/i) !== null) {
		return filename.match(/\.([a-z0-9]+)(&loop.*)?$/i)[1];
	} else if (filename.match(/https?:\/\/(www\.)?youtube.com/)) {
		return 'Youtube';
	} else {
		return "unknown: " + filename;
	}
}

function isImage(fileExtension) { //Pashe, WTFPL
	return ($.inArray(fileExtension, ["jpg", "jpeg", "gif", "png"]) !== -1);
}

function isVideo(fileExtension) { //Pashe, WTFPL
	return ($.inArray(fileExtension, ["webm", "mp4"]) !== -1);
}

function isOnCatalog() {
	return window.active_page === "catalog";
}

function isOnThread() {
	return window.active_page === "thread";
}

function resolveFullImageUrl($thumb) {
	if (isOnCatalog()) {
		return $thumb.attr("data-fullimage") || null;
	}

	var $file = $thumb.closest(".file, .files > div, .post, .thread");
	var $fileInfoLink = $file.find("p.fileinfo a").first();

	if ($fileInfoLink.length && $fileInfoLink.attr("href")) {
		return $fileInfoLink.attr("href");
	}

	var $link = $thumb.closest("a");
	if ($link.length && $link.attr("href")) {
		return $link.attr("href");
	}

	return null;
}

function getSetting(key) {
	return (localStorage[key] == 'true');
}

function initImageHover() { //Pashe, influenced by tux, et al, WTFPL
	if (!getSetting("imageHover") && !getSetting("catalogImageHover")) {return;}
	
	var selectors = [];
	
	if (getSetting("imageHover")) {selectors.push("img.post-image", "canvas.post-image");}
	if (getSetting("catalogImageHover") && isOnCatalog()) {
		selectors.push(".thread-image");
		$(".theme-catalog div.thread").css("position", "inherit");
	}
	
	function bindEvents(el) {
		$(el).find(selectors.join(", ")).each(function () {
			if ($(this).parent().data("expanded")) {return;}
			
			var $this = $(this);
			
			$this.on("mousemove", imageHoverStart);
			$this.on("mouseout",  imageHoverEnd);
			$this.on("click",     imageHoverEnd);
		});
	}

	window.bind_image_hover = bindEvents;

	bindEvents(document.body);
	$(document).on('new_post', function(e, post) {
		bindEvents(post);
	});
}

function imageHoverStart(e) { //Pashe, anonish, WTFPL
	var hoverImage = $("#chx_hoverImage");
	var $this = $(this);

	if ($this.hasClass('yt-embed') || $this.closest('.video-container').length) {
		return;
	}
	
	if (hoverImage.length) {
		if (getSetting("imageHoverFollowCursor")) {
			positionHoverImage(hoverImage, e);
		}
		
		return;
	}

	var fullUrl = resolveFullImageUrl($this);

	if (isOnCatalog() && fullUrl && !isImage(getFileExtension(fullUrl))) {
		fullUrl = $this.attr("src");
	}

	if (!fullUrl) {return;}
	
	if (isVideo(getFileExtension(fullUrl))) {return;}
	
	hoverImage = $('<img id="chx_hoverImage" src="'+fullUrl+'" />');

	if (getSetting("imageHoverFollowCursor")) {
		hoverImage.css({
			"position"      : "fixed",
			"z-index"       : 101,
			"pointer-events": "none",
			"max-width"     : "70vw",
			"max-height"    : "70vh",
		});
	} else {
		hoverImage.css({
			"position"      : "fixed",
			"top"           : 0,
			"right"         : 0,
			"z-index"       : 101,
			"pointer-events": "none",
			"max-width"     : "100%",
			"max-height"    : "100%",
		});
	}
	hoverImage.appendTo($("body"));
	if (getSetting("imageHoverFollowCursor")) {
		positionHoverImage(hoverImage, e);
	}
}

function imageHoverEnd() { //Pashe, WTFPL
	$("#chx_hoverImage").remove();
}

function positionHoverImage(hoverImage, e) {
	var offset = 20;
	var left = e.clientX + offset;
	var top = e.clientY + offset;
	var windowWidth = $(window).width();
	var windowHeight = $(window).height();
	var imageWidth = hoverImage.outerWidth() || 0;
	var imageHeight = hoverImage.outerHeight() || 0;

	if (left + imageWidth > windowWidth - 10) {
		left = Math.max(10, e.clientX - imageWidth - offset);
	}

	if (top + imageHeight > windowHeight - 10) {
		top = Math.max(10, windowHeight - imageHeight - 10);
	}

	hoverImage.css({
		left: left,
		top: top
	});
}

initImageHover();
});
}
/* End js/image-hover.js */

/* Begin js/show-own-posts.js */
/*
 * show-own-posts.js
 * https://github.com/savetheinternet/Tinyboard/blob/master/js/show-op.js
 *
 * Adds "(You)" to a name field when the post is yours. Update references as well.
 *
 * Released under the MIT license
 * Copyright (c) 2014 Marcin Łabanowski <marcin@6irc.net>
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   $config['additional_javascript'][] = 'js/ajax.js';
 *   $config['additional_javascript'][] = 'js/show-own-posts.js';
 *
 */


+function(){


var update_own = function() {
  if ($(this).is('.you')) return;

  var thread = $(this).parents('[id^="thread_"]').first();
  if (!thread.length) {
    thread = $(this);
  }

  var board = thread.attr('data-board');
  var posts = JSON.parse(localStorage.own_posts || '{}');

  var id = $(this).attr('id').split('_')[1];

  if (posts[board] && posts[board].indexOf(id) !== -1) { // Own post!
    $(this).addClass('you');
    $(this).find('span.name').first().append(' <span class="own_post">'+_('(You)')+'</span>');
  }

  // Update references
  $(this).find('div.body:first a:not([rel="nofollow"])').each(function() {
    var postID;

    if(postID = $(this).text().match(/^>>(\d+)$/))
      postID = postID[1];
    else
      return;

    if (posts[board] && posts[board].indexOf(postID) !== -1) {
      $(this).after(' <small>'+_('(You)')+'</small>');
    }
  });
};

var update_all = function() {
  $('div[id^="thread_"], div.post.reply').each(update_own);
};

var board = null;

$(function() {
  board = $('input[name="board"]').first().val();

  update_all();
});

$(document).on('ajax_after_post', function(e, r) {
  var posts = JSON.parse(localStorage.own_posts || '{}');
  posts[board] = posts[board] || [];
  posts[board].push(r.id);
  localStorage.own_posts = JSON.stringify(posts);
});

$(document).on('new_post', function(e,post) {
  var $post = $(post);
  if ($post.is('div.post.reply')) { // it's a reply
    $post.each(update_own);
  }
  else {
    $post.each(update_own); // first OP
    $post.find('div.post.reply').each(update_own); // then replies
  }
});



}();
/* End js/show-own-posts.js */

/* Begin js/show-own-posts-options.js */
if (active_page === 'thread' || active_page === 'index' || active_page === 'catalog' || active_page === 'ukko') {
  document.addEventListener('DOMContentLoaded', function () {
    if (!(window.Options && Options.get_tab('general'))) return;
    var runtime = window.EirinchanRuntime || {};
    var readCookie = runtime.readCookie || function(name, fallback) {
      var match = document.cookie.match(new RegExp('(?:^|; )' + name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '=([^;]*)'));
      return match ? decodeURIComponent(match[1]) : fallback;
    };
    var writeCookie = runtime.writeCookie || function(name, value) {
      document.cookie = name + '=' + encodeURIComponent(value) + '; path=/; max-age=31536000; samesite=lax';
    };

    Options.extend_tab(
      'general',
      '<label id="show-yous"><input type="checkbox">' + _('Show (You)s') + '</label>'
    );

    var enabled = readCookie('show_yous', 'true') !== 'false';
    $('#show-yous>input').prop('checked', enabled);

    $('#show-yous>input').on('click', function () {
      var value = $('#show-yous>input').is(':checked') ? 'true' : 'false';
      writeCookie('show_yous', value, { path: '/', maxAge: 31536000, sameSite: 'lax' });
      location.reload();
    });
  });
}
/* End js/show-own-posts-options.js */

/* Begin js/fix-report-delete-submit.js */
/*
 * fix-report-delete-submit.js
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   $config['additional_javascript'][] = 'js/post-menu.js';
 *   $config['additional_javascript'][] = 'js/fix-report-delete-submit.js';
 *
 */

if (active_page == 'thread' || active_page == 'index' || active_page == 'ukko') {
$(document).on('menu_ready', function(){
var Menu = window.Menu;
if (!Menu || Menu.__quickActionMenuInstalled) {
	return;
}
Menu.__quickActionMenuInstalled = true;

function ensureQuickActionForm($post, postId) {
	var $checkbox = $('#delete_' + postId);
	if ($checkbox.length && !$checkbox.prop('checked')) {
		$checkbox.prop('checked', true).trigger('change');
	}

	var $quickForm = $post.find('form.post-actions');
	if ($quickForm.length) {
		return $quickForm;
	}

	var $sharedForm = $('form[name="postcontrols"]:first');
	if ($sharedForm.length) {
		if (!$sharedForm.find('input[name="delete_post_id"]').length) {
			$sharedForm.prepend('<input type="hidden" name="delete_post_id" value="">');
		}

		if (!$sharedForm.find('input[name="report_post_id"]').length) {
			$sharedForm.prepend('<input type="hidden" name="report_post_id" value="">');
		}
	}

	return $sharedForm;
}

function prepareSharedActionForm($form, postId, action) {
	if (!$form.length || $form.hasClass('post-actions')) {
		return;
	}

	var $deletePostId = $form.find('input[name="delete_post_id"]').first();
	var $reportPostId = $form.find('input[name="report_post_id"]').first();

	if (action === 'delete') {
		$deletePostId.val(postId);
		$reportPostId.val('');
	} else if (action === 'report') {
		$reportPostId.val(postId);
		$deletePostId.val('');
	}
}
	
if ($('#delete-fields #password').length) {
	Menu.add_item("delete_post_menu", _("Delete post"));
	Menu.add_item("delete_file_menu", _("Delete file"));
Menu.onclick(function(e, $buf) {
		var ele = e.target.dataset.postTarget ? document.getElementById(e.target.dataset.postTarget) : $(e.target).closest('.post')[0];
		var $ele = $(ele);
		var postId = $ele.find('.post_no').not('[id]').text();
		var hasFiles = $ele.find('.files .file, .files .multifile').length > 0;

		if (!hasFiles) {
			$buf.find('#delete_file_menu').addClass('hidden');
		}

		$buf.find('#delete_post_menu,#delete_file_menu').click(function(e) {
			e.preventDefault();
			var $form = ensureQuickActionForm($ele, postId);

			if (!$form.length) {
				return;
			}

			prepareSharedActionForm($form, postId, 'delete');

			var $fileToggle = $form.find('#delete_file_' + postId + ', #delete_file, input[name="file"]').first();
			var $password = $form.find('input[name="password"]');
			var passwordValue = $.trim($password.val() || '');
			if ($(this).attr('id') === 'delete_file_menu') {
				$fileToggle.prop('checked', true);
			} else {
				$fileToggle.prop('checked', false);
			}

			if (passwordValue.length) {
				$form.find('input[name="delete"]').trigger('click');
			} else {
				$password.trigger('focus');
			}
		});
	});
}

Menu.add_item("report_menu", _("Report"));
//Menu.add_item("global_report_menu", _("Global report"));
Menu.onclick(function(e, $buf) {
	var ele = e.target.dataset.postTarget ? document.getElementById(e.target.dataset.postTarget) : $(e.target).closest('.post')[0];
	var $ele = $(ele);
	var postId = $ele.find('.post_no').not('[id]').text();

	$buf.find('#report_menu,#global_report_menu').click(function(e) {
		e.preventDefault();
		var $form = ensureQuickActionForm($ele, postId);

		if (!$form.length) {
			return;
		}

		prepareSharedActionForm($form, postId, 'report');
		$form.find('input[name="reason"]').trigger('focus');
	});
});

$('#post-moderation-fields').hide();
});

if (typeof window.Menu !== "undefined") {
	$(document).trigger('menu_ready');
}
}
/* End js/fix-report-delete-submit.js */

/* Begin js/catalog.js */
if (active_page == 'catalog') {
	onReady(function() {
		'use strict';

		var catalog;
		try {
			catalog = localStorage.catalog !== undefined ? JSON.parse(localStorage.catalog) : {};
		} catch (_err) {
			catalog = {};
		}

		function saveCatalogState() {
			localStorage.catalog = JSON.stringify(catalog);
		}

		function currentCatalogBase() {
			var sort = document.getElementById('sort_by');
			return sort && sort.dataset && sort.dataset.catalogBase ? sort.dataset.catalogBase : window.location.pathname;
		}

		function currentSearchValue() {
			var field = document.getElementById('search_field');
			return field ? field.value.trim() : '';
		}

		function navigateCatalog(params) {
			var url = new URL(currentCatalogBase(), window.location.origin);

			if (params.sort_by && params.sort_by !== 'bump:desc') {
				url.searchParams.set('sort_by', params.sort_by);
			}

			if (params.search) {
				url.searchParams.set('search', params.search);
			}

			window.location.assign(url.toString());
		}

		$("#sort_by").change(function() {
			var value = this.value || 'bump:desc';
			catalog.sort_by = value;
			saveCatalogState();
			navigateCatalog({ sort_by: value, search: currentSearchValue() });
		});

		$("#image_size").change(function() {
			var value = this.value;
			$(".grid-li").removeClass("grid-size-vsmall");
			$(".grid-li").removeClass("grid-size-small");
			$(".grid-li").removeClass("grid-size-large");
			$(".grid-li").addClass("grid-size-" + value);
			catalog.image_size = value;
			saveCatalogState();
		});

		if (catalog.image_size !== undefined) {
			$('#image_size').val(catalog.image_size).trigger('change');
		}
	});
}
/* End js/catalog.js */

/* Begin js/catalog-search.js */
if (active_page == 'catalog') {
	onReady(function() {
		'use strict';

		var useKeybinds = true;
		var delay = 400;
		var timeoutHandle;

		function catalogBase() {
			var sort = document.getElementById('sort_by');
			return sort && sort.dataset && sort.dataset.catalogBase ? sort.dataset.catalogBase : window.location.pathname;
		}

		function currentSortValue() {
			var sort = document.getElementById('sort_by');
			return sort ? (sort.value || 'bump:desc') : 'bump:desc';
		}

		function currentSearchField() {
			return document.getElementById('search_field');
		}

		function navigateCatalog(searchTerm) {
			var url = new URL(catalogBase(), window.location.origin);
			var sortBy = currentSortValue();
			var trimmedSearch = (searchTerm || '').trim();

			if (sortBy && sortBy !== 'bump:desc') {
				url.searchParams.set('sort_by', sortBy);
			}

			if (trimmedSearch !== '') {
				url.searchParams.set('search', trimmedSearch);
			}

			window.location.assign(url.toString());
		}

		function ensureField() {
			var field = currentSearchField();
			if (field) return field;

			var container = document.querySelector('.catalog_search');
			if (!container) return null;

			field = document.createElement('input');
			field.id = 'search_field';
			field.autocomplete = 'off';
			field.style.border = 'inset 1px';
			container.appendChild(document.createTextNode(' '));
			container.appendChild(field);
			return field;
		}

		function closeSearch(clearSearch) {
			var button = $('#catalog_search_button');
			var field = currentSearchField();

			button.removeData('expanded');
			button.text('Search');

			if (field) {
				field.remove();
			}

			window.clearTimeout(timeoutHandle);

			if (clearSearch) {
				navigateCatalog('');
			}
		}

		function openSearch() {
			var button = $('#catalog_search_button');
			var field = ensureField();

			button.data('expanded', '1');
			button.text('Close');

			if (field) {
				field.focus();
				field.setSelectionRange(field.value.length, field.value.length);
			}
		}

		function searchToggle() {
			if ($('#catalog_search_button').data('expanded')) {
				closeSearch(true);
			} else {
				openSearch();
			}
		}

		$('#catalog_search_button').on('click', function(e) {
			e.preventDefault();
			searchToggle();
		});

		$('.catalog_search').on('keyup', 'input#search_field', function(e) {
			window.clearTimeout(timeoutHandle);
			timeoutHandle = window.setTimeout(navigateCatalog, delay, e.target.value);
		});

		if (useKeybinds) {
			$('body').on('keydown', function(e) {
				if (e.which === 83 && e.target.tagName === 'BODY' && !(e.ctrlKey || e.altKey || e.shiftKey)) {
					e.preventDefault();
					if (currentSearchField()) {
						currentSearchField().focus();
					} else {
						openSearch();
					}
				}
			});

			$('.catalog_search').on('keydown', 'input#search_field', function(e) {
				if (e.which === 27 && !(e.ctrlKey || e.altKey || e.shiftKey)) {
					e.preventDefault();
					closeSearch(true);
				}
			});
		}
	});
}
/* End js/catalog-search.js */
